<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Bot Maze Explorer</title>
    <style>
        body {
            font-family: sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            background-color: #222;
            color: white;
            padding: 10px;
        }
        #game-container {
            display: flex;
            gap: 30px;
            margin-top: 20px;
        }
        canvas {
            border: 4px solid #aaa;
            background-color: #1a1a1a;
            box-shadow: 0 0 15px rgba(0, 0, 0, 0.5);
        }
        #controls {
            display: flex;
            flex-direction: column;
            gap: 10px;
            width: 200px;
        }
        .info-panel {
            background-color: #333;
            padding: 15px;
            border-radius: 8px;
            box-shadow: 0 4px 8px rgba(0, 0, 0, 0.3);
        }
